class Solution(object):
    def avoidFlood(self, rains):
        lake_date = {}
        full_lakes = set()
        dry_days = []
        result = [-1] * len(rains)
        for i, rain in enumerate(rains):
            if rain == 0:
                dry_days.append(i)
            else:
                if rain in full_lakes:
                    if not dry_days:
                        return []
                    day_to_dry = dry_days.pop()
                    result[day_to_dry] = rain
                    if lake_date[rain] > day_to_dry:
                        return []
                full_lakes.add(rain)
                lake_date[rain] = i
        return result
